<?php
namespace App\Http\Controllers; use App\Models\{Account,ExchangeTransaction,CurrencyRate}; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB;
class ExchangeTransactionController extends Controller {
    public function create(){ $accounts=Account::orderBy('name')->get(); $rate=CurrencyRate::where('active',true)->orderByDesc('valid_from')->first(); return view('exchange.create',compact('accounts','rate')); }
    public function store(Request $r){ $data=$r->validate(['origin_id'=>'required|different:target_id|exists:accounts,id','target_id'=>'required|exists:accounts,id','direction'=>'required|in:usd_to_ves,ves_to_usd','amount'=>'required|numeric|min:0.01','reference'=>'nullable|string|max:200']); $rate=CurrencyRate::where('active',true)->orderByDesc('valid_from')->first(); if(!$rate){ return back()->withErrors(['rate'=>'No hay tasa activa']); } $origin=Account::findOrFail($data['origin_id']); $target=Account::findOrFail($data['target_id']); DB::transaction(function() use($data,$rate,$origin,$target){ if($data['direction']==='usd_to_ves'){ if($origin->balance_usd < $data['amount']){ abort(422,'Fondos insuficientes USD'); } $usd=$data['amount']; $ves=round($usd*$rate->rate,2); $origin->decrement('balance_usd',$usd); $target->increment('balance_ves',$ves); ExchangeTransaction::create(['account_origin_id'=>$origin->id,'account_target_id'=>$target->id,'rate'=>$rate->rate,'amount_origin_usd'=>$usd,'amount_origin_ves'=>0,'amount_target_usd'=>0,'amount_target_ves'=>$ves]); } else { if($origin->balance_ves < $data['amount']){ abort(422,'Fondos insuficientes VES'); } $ves=$data['amount']; $usd=round($ves/$rate->rate,2); $origin->decrement('balance_ves',$ves); $target->increment('balance_usd',$usd); ExchangeTransaction::create(['account_origin_id'=>$origin->id,'account_target_id'=>$target->id,'rate'=>$rate->rate,'amount_origin_usd'=>0,'amount_origin_ves'=>$ves,'amount_target_usd'=>$usd,'amount_target_ves'=>0]); } }); return redirect()->route('accounts.index')->with('status','Cambio realizado'); }
}
